// ----------------------------------------------------------------------------
// Destination data — content only.
//
// IMAGE POLICY: This file intentionally contains NO image URLs.
// All destination, place, hero, gallery and card imagery is centrally managed
// in `src/lib/imageRegistry.ts`. Read images via:
//   getCountryCover(countrySlug)
//   getPlaceHero(countrySlug, placeSlug)
//   getPlaceGallery(countrySlug, placeSlug)
// ----------------------------------------------------------------------------

export interface PlaceDetail {
  id: string;
  name: string;
  country: string;
  countrySlug: string;
  region: "South Asia" | "Southeast Asia" | "India" | "Pilgrimage";
  tagline: string;
  description: string;
  bestTimeToVisit: { months: string; reason: string; avoid: string };
  howToReach: { byAir: string; byRoad: string; byTrain: string; localTransport: string };
  entryFee: { indian: string; foreigner: string; note: string };
  duration: string;
  difficulty: "Easy" | "Moderate" | "Challenging";
  category: string[];
  highlights: string[];
  travelTips: string[];
  nearbyPlaces: string[];
  mustTry: { food: string[]; activity: string[]; shopping: string[] };
  weather: { summer: string; winter: string; monsoon: string };
}

export interface Country {
  slug: string;
  name: string;
  flag: string;
  region: "South Asia" | "Southeast Asia" | "India" | "Pilgrimage";
  overview: string;
  places: PlaceDetail[];
}

// Helper to build a rich place entry without repeating boilerplate
const mk = (
  base: {
    id: string; name: string; country: string; countrySlug: string;
    region: Country["region"]; tagline: string; description: string;
    category: string[]; highlights: string[]; tips: string[]; nearby: string[];
    food: string[]; activity: string[]; shopping: string[];
    months: string; reasonBest: string; avoid: string;
    byAir: string; byRoad: string; byTrain: string; local: string;
    feeIndian: string; feeForeign: string; feeNote: string;
    duration: string; difficulty: PlaceDetail["difficulty"];
    summer: string; winter: string; monsoon: string;
  }
): PlaceDetail => ({
  id: base.id, name: base.name, country: base.country, countrySlug: base.countrySlug,
  region: base.region, tagline: base.tagline, description: base.description,
  bestTimeToVisit: { months: base.months, reason: base.reasonBest, avoid: base.avoid },
  howToReach: { byAir: base.byAir, byRoad: base.byRoad, byTrain: base.byTrain, localTransport: base.local },
  entryFee: { indian: base.feeIndian, foreigner: base.feeForeign, note: base.feeNote },
  duration: base.duration, difficulty: base.difficulty, category: base.category,
  highlights: base.highlights, travelTips: base.tips, nearbyPlaces: base.nearby,
  mustTry: { food: base.food, activity: base.activity, shopping: base.shopping },
  weather: { summer: base.summer, winter: base.winter, monsoon: base.monsoon },
});

// Country-level generators to keep file tractable while still rich + distinct
function makeCountry(opts: {
  slug: string; name: string; flag: string; region: Country["region"];
  overview: string;
  baseAir: string; baseTrain: string; baseRoad: string; baseLocal: string;
  baseMonths: string; baseReason: string; baseAvoid: string;
  baseSummer: string; baseWinter: string; baseMonsoon: string;
  food: string[]; shopping: string[];
  places: { name: string; tagline: string; description: string; category: string[]; highlights: string[]; activity: string[]; nearby: string[]; difficulty?: PlaceDetail["difficulty"]; duration?: string; feeIndian?: string; feeForeign?: string; feeNote?: string }[];
}): Country {
  return {
    slug: opts.slug, name: opts.name, flag: opts.flag, region: opts.region,
    overview: opts.overview,
    places: opts.places.map((p, i) => mk({
      id: `${opts.slug}-${i + 1}`, name: p.name, country: opts.name, countrySlug: opts.slug,
      region: opts.region, tagline: p.tagline, description: p.description,
      category: p.category, highlights: p.highlights,
      tips: [
        "Carry sunscreen, sunglasses & a refillable water bottle.",
        "Respect local customs and dress modestly at religious sites.",
        "Keep small currency for tickets and tips handy.",
        "Hire a licensed local guide for deeper context.",
        "Start early to avoid crowds and harsh midday heat.",
        "Keep digital + printed copies of important documents.",
      ],
      nearby: p.nearby,
      food: opts.food,
      activity: p.activity,
      shopping: opts.shopping,
      months: opts.baseMonths, reasonBest: opts.baseReason, avoid: opts.baseAvoid,
      byAir: opts.baseAir, byRoad: opts.baseRoad, byTrain: opts.baseTrain, local: opts.baseLocal,
      feeIndian: p.feeIndian ?? "Approx ₹200–₹500 per person",
      feeForeign: p.feeForeign ?? "Approx $10–$25 per person",
      feeNote: p.feeNote ?? "Carry a valid photo ID. Camera fees may apply separately.",
      duration: p.duration ?? "2–4 hours",
      difficulty: p.difficulty ?? "Easy",
      summer: opts.baseSummer, winter: opts.baseWinter, monsoon: opts.baseMonsoon,
    })),
  };
}


