export function getCountryBySlug(slug: string) {
  return COUNTRIES.find((c) => c.slug === slug);
}

export function getPlace(countrySlug: string, placeSlug: string) {
  const country = getCountryBySlug(countrySlug);
  if (!country) return null;
  const place = country.places.find((p) => placeNameToSlug(p.name) === placeSlug);
  return place ? { country, place } : null;
}

export function placeNameToSlug(name: string): string {
  return name.toLowerCase().replace(/&/g, "and").replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");
}

export function getAllPlaces(): PlaceDetail[] {
  return COUNTRIES.flatMap((c) => c.places);
}
